using TMPro;
using UnityEngine;
using UnityEngine.UI;

/// <summary>
/// Um "nó" (ícone) da Roda de Itens (<see cref="ItemWheelUI"/>): representa um
/// item utilizável (<see cref="ItemData.usableByPlayer"/>) presente no
/// inventário do jogador, com a respectiva quantidade.
///
/// Estados visuais:
/// - Equipado: <see cref="equippedMarker"/> activo (este é o
///   "equippedItemId" actual).
/// - Seleccionado na roda: <see cref="selectionHighlight"/> activo (destaque
///   do nó sob a navegação).
/// </summary>
public class ItemWheelNodeUI : MonoBehaviour
{
    [Header("Visual")]
    public Image icon;

    [Tooltip("Quantidade do item no inventário (ex: \"x18\").")]
    public TMP_Text quantityText;

    [Tooltip("Destaque (anel/glow) activo quando este nó é o seleccionado na roda.")]
    public Image selectionHighlight;

    [Tooltip("Marcador pequeno activo quando este item é o equipado actualmente (PlayerProgress.equippedItemId).")]
    public Image equippedMarker;

    public ItemData Item { get; private set; }

    public void Setup(ItemData item, int quantity, bool isEquipped, bool isSelected)
    {
        Item = item;

        if (icon != null) icon.sprite = item != null ? item.icon : null;
        if (quantityText != null) quantityText.text = $"x{quantity}";
        if (selectionHighlight != null) selectionHighlight.enabled = isSelected;
        if (equippedMarker != null) equippedMarker.enabled = isEquipped;
    }
}
